hr.script:
(function(){
  const c = document.getElementById('stars');
  const ctx = c.getContext('2d');
  let w, h, stars = [];

  function resize() {
    w = c.width = window.innerWidth;
    h = c.height = window.innerHeight;
  }

  function mkStars() {
    stars = [];
    for (let i = 0; i < 280; i++) {
      stars.push({
        x: Math.random() * w,
        y: Math.random() * h,
        r: Math.random() * 1.2 + 0.2,
        a: Math.random(),
        s: (Math.random() - 0.5) * 0.15
      });
    }
  }

  function draw() {
    ctx.clearRect(0, 0, w, h);
    stars.forEach(s => {
      s.a += s.s * 0.01;
      if (s.a < 0) s.a = 0.8;
      if (s.a > 1) s.a = 0.2;
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(200,210,240,${s.a})`;
      ctx.fill();
    });
    requestAnimationFrame(draw);
  }

  resize(); mkStars(); draw();
  window.addEventListener('resize', () => { resize(); mkStars(); });
})();
